class Solution {
    public double minTime(int n, int k, int m, int[] time, double[] mul) {
        double[][] dp = new double[n + 1][m];
        for (double[] row : dp) {
            Arrays.fill(row, Double.MAX_VALUE);
        }
        dp[0][0] = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (dp[i][j] == Double.MAX_VALUE) continue;
                for (int p = 1; p <= Math.min(k, n - i); p++) {
                    int[] group = new int[p];
                    for (int l = 0; l < p; l++) {
                        group[l] = time[i + l];
                    }
                    Arrays.sort(group);
                    double timeToCross = group[p - 1] * mul[j];
                    int nextStage = (j + (int) timeToCross % m) % m;
                    double returnTime = Double.MAX_VALUE;
                    if (p < k) {
                        returnTime = time[i] * mul[nextStage];
                    }
                    dp[i + p][nextStage] = Math.min(dp[i + p][nextStage], dp[i][j] + timeToCross + returnTime);
                }
            }
        }
        if (dp[n][0] == Double.MAX_VALUE) return -1;
        return dp[n][0];
    }
}
